/**
 * Self-contained decomposition topology test.
 *
 * Run:
 *   pnpm run gnode -- run open-source/gnosis/src/__tests__/decomposition-topology.test.ts
 */

import assert from 'node:assert';
import {
  decompositionDoesNotIncreaseCrossings,
  decompositionReleasesNonnegativeResidue,
  decompose,
  featurelessDecompositionIdempotent,
  fullDecompositionYieldsFeatureless,
  isFeatureless,
} from '../decomposition-topology';

const steelBlade = {
  crossings: 7,
  weight: 10,
  capacity: 12,
};

const partial = decompose(steelBlade, 3);
assert.deepStrictEqual(partial, {
  residualCrossings: 4,
  releasedWeight: 3,
  residueUnits: 0,
  residualWeight: 7,
});
assert.strictEqual(decompositionDoesNotIncreaseCrossings(steelBlade, 3), true);
assert.strictEqual(
  decompositionReleasesNonnegativeResidue(steelBlade, 3),
  true
);

const full = decompose(steelBlade, 9);
assert.deepStrictEqual(full, {
  residualCrossings: 0,
  releasedWeight: 9,
  residueUnits: 2,
  residualWeight: 1,
});
assert.strictEqual(fullDecompositionYieldsFeatureless(steelBlade, 9), true);

const featurelessDust = {
  crossings: 0,
  weight: 5,
  capacity: 3,
};

assert.strictEqual(isFeatureless(featurelessDust), true);
assert.strictEqual(
  featurelessDecompositionIdempotent(featurelessDust, 4),
  true
);
assert.deepStrictEqual(decompose(featurelessDust, 4), {
  residualCrossings: 0,
  releasedWeight: 4,
  residueUnits: 4,
  residualWeight: 1,
});

console.log('decomposition-topology: all tests passed');
